// src/pages/PatientLogin.jsx
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Box,
  Alert,
} from "@mui/material";
import PersonIcon from "@mui/icons-material/Person";
import { useAuth } from "../context/AuthContext";

export default function PatientLogin() {
  const [email, setEmail] = useState("");
  const [error, setError] = useState("");
  const navigate = useNavigate();
  const { loginPatient } = useAuth();

  const handleLogin = (e) => {
    e.preventDefault();
    if (!email || !email.includes("@")) {
      setError("Please enter a valid email address");
      return;
    }

    loginPatient(email);
    navigate("/patient"); // Go to patient dashboard after login
  };

  return (
    <Container maxWidth="sm" sx={{ py: 12 }}>
      <Paper elevation={6} sx={{ p: 6, borderRadius: 4, textAlign: "center" }}>
        <PersonIcon sx={{ fontSize: 70, color: "#1976d2", mb: 2 }} />
        <Typography variant="h4" fontWeight={700} gutterBottom>
          Patient Login
        </Typography>
        <Typography color="text.secondary" sx={{ mb: 4 }}>
          Enter your email to continue
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 3 }}>
            {error}
          </Alert>
        )}

        <form onSubmit={handleLogin}>
          <TextField
            fullWidth
            label="Email Address"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="example@email.com"
            sx={{ mb: 3 }}
            required
          />

          <Button
            type="submit"
            fullWidth
            variant="contained"
            size="large"
            sx={{ py: 1.5, borderRadius: 3, fontWeight: 600 }}
          >
            Login as Patient
          </Button>
        </form>

        <Typography variant="body2" color="text.secondary" sx={{ mt: 4 }}>
          Any valid email works • No password required
        </Typography>
      </Paper>
    </Container>
  );
}
